const body = $input.item.json.body;
const toNumber = body.To || '';
const fromNumber = body.From || '';
const messageBody = body.Body || '';
const fromClean = fromNumber.replace('whatsapp:', '');
const fromEncoded = '%2B' + fromClean.replace('+', '');
return [{ json: {
  to_number: toNumber,
  from_number: fromNumber,
  message_body: messageBody,
  to_encoded: encodeURIComponent(toNumber),
  from_clean: fromClean,
  from_encoded: fromEncoded
}}];

const company = $('Supabase — Firmayı Bul').item.json[0] || $('Supabase — Firmayı Bul').item.json;
const wh = $('Webhook Verisini Hazırla').item.json;
const firm = Array.isArray($('Supabase — Firmayı Bul').all()[0].json) 
  ? $('Supabase — Firmayı Bul').all()[0].json[0]
  : $('Supabase — Firmayı Bul').all()[0].json;
return [{ json: {
  company_id: firm.id,
  company_name: firm.name,
  whatsapp_number: firm.whatsapp_number,
  whatsapp_number_clean: firm.whatsapp_number.replace('whatsapp:', ''),
  from_clean: wh.from_clean,
  from_encoded: wh.from_encoded,
  from_number: wh.from_number,
  message_body: wh.message_body,
  to_number: wh.to_number
}}];

const ctx = $('Bağlam Hazırla').item.json;
const allItems = $('Supabase — Mevcut Müşteri Bul').all();
const raw = allItems.length > 0 ? allItems[0].json : {};
const client = Array.isArray(raw) ? (raw[0] || null) : (raw && raw.id ? raw : null);
const clientName = client ? (client.full_name || '') : '';
const clientId = client ? client.id : null;
const companyName = ctx.company_name || 'Vize Danışmanlık';
const hitap = 'efendim';
const portalBaseUrl = 'https://app.vectropus.com';
const portalLink = client?.portal_token ? `${portalBaseUrl}/portal/${client.portal_token}` : null;

const sys = `Sen ${companyName} firmasının WhatsApp asistanısın. Türkçe yaz, kısa ve samimi ol. Emoji kullanma.
Bu kişi firmanın kayıtlı müşterisidir. "${hitap}" olarak hitap et.
Görevin: Sorusunu anlayıp yardımcı olmak. Vize başvurusu, randevu, evrak konularında genel bilgi ver. Ayrıntılar için danışmanları yönlendir.
KURALLAR:
KURAL 1 — PORTAL LİNKİ: Müşteri "portal linki", "linkimi at", "portal adresim", "nasıl gireceğim" diye sorarsa direkt portal linkini ver (${portalLink || 'portal linki bilgisi mevcut değil'}). "Danışmanınıza ileteceğim" DEME.
- Kesin tarih, süre veya fiyat bilgisi verme
- Cevapları kısa tut (1-3 cümle)
- Her zaman nazik ve profesyonel ol
YANIT FORMATI: Yanıtını SADECE şu JSON formatında ver, başka hiçbir şey yazma:
{"response": "WhatsApp mesajın buraya"}

ÖRNEK KONUŞMALAR (bu örneklere göre cevap ver):

Müşteri: Evraklarım tamam mı?
Asistan: Evrak durumunuzu portal üzerinden takip edebilirsiniz efendim. Eksik evraklar portalda kırmızı görünecektir.

Müşteri: Randevum ne zaman?
Asistan: Randevu bilgileriniz portala yansıtılmaktadır efendim. Danışmanınız randevu aldığında sizi ayrıca bilgilendirecektir.

Müşteri: Vizem çıktı mı?
Asistan: Vize sonucu konsolosluktan geldiği anda danışmanınız sizi arayacaktır efendim. Pasaport teslimi de aynı şekilde bildirilecektir.

Müşteri: Portal şifrem ne?
Asistan: Portala şifre gerekmez efendim, size özel link üzerinden direkt giriş yapabilirsiniz.

Müşteri: Ne zaman arayacaklar?
Asistan: Danışmanınız mesai saatlerinde (09:00-18:00) sizinle iletişime geçecektir efendim.

Müşteri: Kaç aylık banka ekstresi lazım?
Asistan: Genellikle son 3-6 aylık ekstre istenmektedir efendim, ancak kesin liste için portaldaki evrak listesini inceleyebilirsiniz.

Müşteri: İptal etmek istiyorum.
Asistan: İptal talebinizi danışmanınıza iletmem için not aldım efendim. En kısa sürede sizinle iletişime geçilecektir.

Müşteri: Seyahat tarihim yaklaşıyor, yetişir mi?
Asistan: Bu konuyu danışmanınıza acil olarak iletiyorum efendim. Lütfen danışmanınızı mesai saatlerinde (09:00-18:00) arayın.

Müşteri: Konsoloslukta ne yapacağım?
Asistan: Konsolosluk randevusunda pasaportunuzu, fotoğrafınızı ve onaylı evraklarınızı yanınızda bulundurmanız yeterlidir efendim. Danışmanınız öncesinde detaylı bilgi verecektir.

Müşteri: Reddettiyseler ne olacak?
Asistan: Ret durumunda danışmanınız sizinle iletişime geçerek sonraki adımları değerlendirecektir efendim.

Müşteri: Linkimi atar mısın?
Asistan: Portal linkiniz: ${portalLink} efendim.

Müşteri: Portala nasıl giriyorum?
Asistan: Portal linkiniz: ${portalLink} efendim. Bu link üzerinden direkt giriş yapabilirsiniz.`;

const messages = [
  { role: 'system', content: sys },
  { role: 'user', content: ctx.message_body }
];
const body = JSON.stringify({ model: 'gpt-4o', messages });

return [{ json: {
  company_id: ctx.company_id,
  company_name: companyName,
  client_id: clientId,
  client_name: clientName,
  from_clean: ctx.from_clean,
  whatsapp_number_clean: ctx.whatsapp_number_clean,
  message_body: ctx.message_body,
  gpt_body_string: body
}}];

const raw = $input.item.json.choices[0].message.content;
const ctx = $('GPT Müşteri Mesajlarını Hazırla').item.json;

let gptResponse;
try {
  const parsed = JSON.parse(raw);
  gptResponse = parsed.response || raw;
} catch(e) {
  gptResponse = raw;
}

return [{ json: {
  whatsapp_number_clean: ctx.whatsapp_number_clean,
  phone_clean: ctx.from_clean,
  gpt_response: gptResponse
}}];

const items = $input.all();
const ctx = $('Bağlam Hazırla').item.json;

let lead_id = null;
let history = [];
let existing_user_message = '';

const lead = (items.length > 0 && items[0].json && items[0].json.id) ? items[0].json : null;

if (lead) {
  lead_id = lead.id;
  existing_user_message = lead.user_message || '';
  const raw = lead.conversation_history;
  if (raw) {
    if (typeof raw === 'string') {
      try { history = JSON.parse(raw); } catch(e) { history = []; }
    } else if (Array.isArray(raw)) {
      history = [...raw];
    }
  }
}

history.push({ role: 'user', content: ctx.message_body });
if (history.length > 20) history = history.slice(-20);

return [{ json: {
  lead_id: lead_id,
  existing_user_message: existing_user_message,
  company_id: ctx.company_id,
  company_name: ctx.company_name,
  phone_clean: ctx.from_clean,
  phone_encoded: ctx.from_encoded,
  whatsapp_number_clean: ctx.whatsapp_number_clean,
  message: ctx.message_body,
  history_for_gpt: history
}}];

const ctx = $input.item.json;
const name = ctx.company_name || 'Vize Danışmanlık';
const hist = Array.isArray(ctx.history_for_gpt) ? ctx.history_for_gpt : [{ role: 'user', content: ctx.message }];

const assistantCount = hist.filter(m => m.role === 'assistant').length;
const isFirstMessage = assistantCount === 0;

let durum = '';
if (isFirstMessage) {
  durum = 'Bu ilk mesajdır. Karşılama yap ve hangi ülke/vize konusunda bilgi almak istediğini sor.';
} else {
  const lastAssistant = hist.filter(m => m.role === 'assistant').pop()?.content || '';
  const isimSoruldu = lastAssistant.includes('sminizi') || lastAssistant.includes('soyisim');
  if (isimSoruldu) {
    durum = 'İsim sorusu sordun. Kullanıcı cevap verdi, ismi al ve teşekkür et, danışmanlar arayacak de.';
  } else {
    durum = 'Konuyu öğrendin. Şimdi isim sor.';
  }
}

const sys = `Sen ${name} firmasının WhatsApp vize danışmanlık asistanısın. Türkçe yaz, kısa ve samimi ol. Emoji kullanma.

MEVCUT DURUM: ${durum}

GÖREV AKIŞI:
Adım 1 → Selamlama/ilk mesaj: Karşıla, ülke ve vize konusunu sor.
Adım 2 → Konu belirtildi: "Tamamdır, not aldım. İsim soyisminizi öğrenebilir miyim?"
Adım 3 → İsim verildi: "Teşekkürler [isim]! Danışmanlarımız sizi en kısa sürede arayacak."
Adım 4 → Sonraki mesajlar: Danışmana yönlendir.

ÖRNEK KONUŞMALAR:

Müşteri: Merhaba
Asistan: {"response": "Merhaba! ${name} olarak size nasıl yardımcı olabiliriz? Hangi ülke ve vize konusunda bilgi almak istiyorsunuz?"}

Müşteri: Almanya vizesi hakkında bilgi almak istiyorum
Asistan: {"response": "Tamamdır, not aldım. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Schengen vizesi almak istiyorum
Asistan: {"response": "Tamamdır, not aldım. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Fransa turistik vize
Asistan: {"response": "Tamamdır, not aldım. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Öğrenci vizesi almak istiyorum
Asistan: {"response": "Hangi ülke için öğrenci vizesi almak istiyorsunuz?"}

Müşteri: Almanya öğrenci vizesi
Asistan: {"response": "Tamamdır, not aldım. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Ahmet Yılmaz
Asistan: {"response": "Teşekkürler Ahmet Yılmaz! Danışmanlarımız sizi en kısa sürede arayacak."}

Müşteri: Ne zaman arayacaklar?
Asistan: {"response": "Danışmanlarımız mesai saatlerinde (09:00-18:00) sizi arayacaktır."}

Müşteri: Fiyat nedir?
Asistan: {"response": "Fiyat bilgisi için danışmanlarımız sizi aradığında detaylı bilgi verecektir. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Vize kaç günde çıkar?
Asistan: {"response": "Vize süreleri başvuruya göre değişmektedir. Danışmanlarımız sizi aradığında detaylı bilgi verecektir."}

Müşteri: Hangi evraklar lazım?
Asistan: {"response": "Evrak listesi ülkeye ve vize türüne göre değişmektedir. Danışmanlarımız sizi aradığında size özel liste hazırlayacaktır."}

Müşteri: Acil vizem lazım
Asistan: {"response": "Acil başvurular için danışmanlarımız en kısa sürede sizi arayacaktır. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Ret yedim ne yapacağım?
Asistan: {"response": "Ret durumunda yeniden başvuru yapılabilir. Danışmanlarımız sizi aradığında durumunuzu değerlendirecektir. İsim soyisminizi öğrenebilir miyim?"}

Müşteri: Teşekkürler
Asistan: {"response": "Rica ederiz! Danışmanlarımız sizi en kısa sürede arayacaktır."}

KURALLAR:
- Geçmişe bak, devam et, başa dönme
- Fiyat bilgisi verme
- Kesin tarih/süre verme
- Her zaman nazik ve profesyonel ol

YANIT FORMATI — SADECE bu JSON'ı döndür, başka hiçbir şey yazma:
{"response": "mesaj buraya"}`;

const body = JSON.stringify({
  model: 'gpt-4o',
  messages: [{ role: 'system', content: sys }, ...hist],
  response_format: { type: 'json_object' }
});

return [{ json: { ...ctx, history_for_gpt: hist, gpt_body_string: body } }];

const raw = $input.item.json.choices[0].message.content;
const ctx = $('GPT Mesajlarını Hazırla').item.json;

let gptResponse;
try {
  const parsed = JSON.parse(raw);
  gptResponse = parsed.response || raw;
} catch(e) {
  gptResponse = raw;
}

let updated = [...(ctx.history_for_gpt || []), { role: 'assistant', content: gptResponse }];
if (updated.length > 20) updated = updated.slice(-20);

let full_name = null;
for (let i = 0; i < updated.length - 1; i++) {
  if (updated[i].role === 'assistant') {
    const content = updated[i].content;
    if (content.indexOf('soyisim') !== -1 || content.indexOf('sminizi') !== -1) {
      if (updated[i + 1] && updated[i + 1].role === 'user') {
        full_name = updated[i + 1].content.trim();
      }
    }
  }
}

const kullaniciMesajlari = updated
  .filter(m => m.role === 'user')
  .map(m => m.content)
  .join('\n');

const anthropicBody = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 100,
  messages: [{
    role: 'user',
    content: 'Aşağıdaki WhatsApp konuşmasında müşterinin ne istediğini tek cümleyle özetle. Sadece vize amacını yaz, isim bilgisi ekleme, "müşteri" kelimesi kullanma. Direkt yaz örnek: "İsviçre öğrenci vizesi için bilgi almak istiyor"\n\nKonuşma:\n' + kullaniciMesajlari
  }]
});

return [{ json: {
  lead_id: ctx.lead_id,
  company_id: ctx.company_id,
  phone_clean: ctx.phone_clean,
  phone_encoded: ctx.phone_encoded,
  whatsapp_number_clean: ctx.whatsapp_number_clean,
  existing_user_message: ctx.existing_user_message,
  message: ctx.message,
  gpt_response: gptResponse,
  updated_history: updated,
  full_name: full_name,
  anthropic_body: anthropicBody
}}];

const ctx = $('Özet Hazırla').item.json;
const anthropicData = $input.item.json;

const user_message = ((anthropicData.content && anthropicData.content[0] && anthropicData.content[0].text)
  || ctx.existing_user_message
  || '').trim().substring(0, 80);

return [{ json: {
  lead_id: ctx.lead_id,
  company_id: ctx.company_id,
  phone_clean: ctx.phone_clean,
  phone_encoded: ctx.phone_encoded,
  whatsapp_number_clean: ctx.whatsapp_number_clean,
  user_message: user_message,
  message: ctx.message,
  gpt_response: ctx.gpt_response,
  updated_history: ctx.updated_history,
  full_name: ctx.full_name
}}];
